var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"선원들! 출항을 준비하라~ 바다에 숨겨진 보물을 찾으러 떠날 시간이 왔다!","JPN":"船員のみんな！　出港の準備をせよ！　海に隠された宝物を探しに出発する時が来た！","ENG":"Get ready, crew! Let’s set sail to find the hidden treasure!","TWN":"船員們！準備出海吧～要去尋找藏在深海裡的寶藏囉！"},"stage":{"bg":"VILLAGE2","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"네, 넵, 선장님!","JPN":"はい、船長！","ENG":"A-aye aye, captain!","TWN":"是，是的，船長！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L7_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"와, 정말 기대돼요. 화물선이 아닌 배를 타보게 되다니.","JPN":"わぁ、本当に楽しみです。貨物船ではない船に乗るのは初めてです。","ENG":"Oh, I’m so excited to be on a ship that’s not a cargo ship.","TWN":"哇，好期待。搭的是客輪不是貨船。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"}}}},{"id":"L10_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"아이들과 놀아주신다니 감사해요.","JPN":"子どもたちと遊んでくれてありがとうございます。","ENG":"Thank you for playing with the children.","TWN":"謝謝你和孩子們一起玩。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"하지만 조금 걱정되네요.","JPN":"でも、少し心配ですわ。","ENG":"But I’m a bit worried.","TWN":"但我有點擔心。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"아이들끼리 저런 큰 배를 가지고 놀게 해도 괜찮을까요?","JPN":"子どもたちだけであんな大きな船で遊ばせてもいいのですか？","ENG":"Are you sure we can let them play on such a big ship all by themselves?","TWN":"小孩子開大船沒問題嗎？"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"그거라면 걱정 마시죠, 어머님.","JPN":"それなら心配しないでください、お母さん。","ENG":"Don’t worry about it, ma’am.","TWN":"伯母放心吧！"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L15_1","type":"dialog","speaker":"MACHINEGAP_COFFIN_NULL_NULL","text":{"KOREA":"저희 애는 차원함선도 세 발 자전거처럼 몰거든요.","JPN":"うちの子は次元艦船も三輪車のように運転できる子なんです。","ENG":"My daughter can drive a dimensional ship like a tricycle.","TWN":"我們家女兒把次元艦船都當成三輪車在開。"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L17_1","type":"dialog","speaker":"MONEMOTHER_NPC_NULL_NULL","text":{"KOREA":"함선…… 을요?","JPN":"艦船……をですか?","ENG":"A... dimensional ship?","TWN":"艦船…喔？"},"stage":{"bg":"VILLAGE2","slots":{"L":{"char_id":"MONEMOTHER_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"MACHINEGAP_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"와아, 이것 좀 보십셔! 선장님이 부르니까 정말 돌고래 떼가 왔슴다! 신기함다!","JPN":"わぁ、これを見てくださいっす！　船長が呼んだら本当にイルカの群れが来たっす！　不思議っす！","ENG":"Wow, look at this, captain! The dolphins are here as you commanded! This is so awesome!","TWN":"哇，大家快看！船長一喊，海豚就來咧！好神奇喔！"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L22_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"선장님은 정말 돌고래랑 대화도 할 수 있는 건가요?","JPN":"船長は本当にイルカと会話ができるんですか？","ENG":"Can you really talk to dolphins, captain?","TWN":"船長真的能和海豚對話嗎？"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"으흠! 물론이지!","JPN":"うん！　もちろん！","ENG":"Of course I can!","TWN":"嗯嗯！當然！"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"진정한 선장이 되려면 동물과의 친해지는 것 정도는 기본 소양이라구!","JPN":"本物の船長になるには動物と仲良くなることぐらい基本素養だよ！","ENG":"To be a captain, you need to be able to befriend animals!","TWN":"要想成爲真正的船長，和動物交朋友是基本的好嗎！"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"저도 책에서 봤어요. 그래서 선장들이 앵무새나 원숭이를 데리고 다니던 거군요.","JPN":"私も本で見ました。だから船長たちはオウムや猿を連れていたのですね。","ENG":"I read it in the books! So that’s why pirate captains always have a parrot or a monkey with them.","TWN":"我也有在書上看過，船長身邊都會跟著鸚鵡或猴子喔！"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L29_1","type":"dialog","speaker":"TONFA_FLORA_SUMMER_NULL","text":{"KOREA":"저도 선장님처럼 돌고래랑 대화하고 싶슴다! 선장님이 가르쳐주면 안 되겠슴까!?","JPN":"モネも船長のようにイルカと会話がしたいっす！　船長、教えてほしいっす！","ENG":"I want to talk to dolphins too, captain! Can you teach me?","TWN":"我也想和船長一樣跟海豚對話！船長可以教我嗎？"},"stage":{"bg":"CRUISE","slots":{"L":{"char_id":"TONFA_FLORA_SUMMER_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L31_1","type":"dialog","speaker":"SIGMA_RAS_SUMMER_NULL","text":{"KOREA":"좋아!","JPN":"いいよ！","ENG":"Okay!","TWN":"好哇！"},"stage":{"bg":"CRUISE","slots":{"L":null,"C":{"char_id":"SIGMA_RAS_SUMMER_NULL","face":"UNIT_LAUGH"},"R":null}}}]`);export{e as default};